 12Ôćĺ} from '@modules/db/style-copurchases/dto/find-top-copurchases.dto';
 13Ôćĺimport { ICopurchaseRow } from '@modules/db/style-copurchases/types/copurchase-row.interface';
 14Ôćĺ
 15Ôćĺimport {
 16Ôćĺ	KNEX_READ_CONNECTION,
 17Ôćĺ	KNEX_WRITE_CONNECTION,
 18Ôćĺ	TABLE_NAME_STYLE_COPURCHASES,
 19Ôćĺ	TABLE_NAME_STYLES_MV,
 20Ôćĺ} from '@constants/db.constant';
