 22Ôćĺ@Injectable()
 23Ôćĺexport class StyleCopurchaseModel {
 24Ôćĺ	private readonly logger = new Logger(StyleCopurchaseModel.name);
 25Ôćĺ	private readonly tableName = TABLE_NAME_STYLE_COPURCHASES;
 26Ôćĺ
 27Ôćĺ	constructor(
 28Ôćĺ		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
 29Ôćĺ		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
 30Ôćĺ	) {}
 31Ôćĺ
 32Ôćĺ	async findTopCopurchases({
 33Ôćĺ		styleId,
 34Ôćĺ		limit = 4,
 35Ôćĺ		excludeIds = [],
 36Ôćĺ	}: {
 37Ôćĺ		styleId: number;
 38Ôćĺ		limit?: number;
 39Ôćĺ		excludeIds?: number[];
 40Ôćĺ	}): Promise<{ paired_style_id: number; copurchase_count: number }[]> {
 41Ôćĺ		const dto = plainToInstance(FindTopCopurchasesDto, { styleId, limit, excludeIds });
 42Ôćĺ		const errors = await validate(dto);
 43Ôćĺ		if (errors.length > 0) {
 44Ôćĺ			throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
 45Ôćĺ		}
 46Ôćĺ
 47Ôćĺ		try {
 48Ôćĺ			const queryA = this.knexRead(this.tableName)
 49Ôćĺ				.select('style_id_b as paired_style_id', 'copurchase_count')
 50Ôćĺ				.where({ style_id_a: styleId })
 51Ôćĺ				.whereNull('deleted_at');
 52Ôćĺ
 53Ôćĺ			const queryB = this.knexRead(this.tableName)
 54Ôćĺ				.select('style_id_a as paired_style_id', 'copurchase_count')
 55Ôćĺ				.where({ style_id_b: styleId })
 56Ôćĺ				.whereNull('deleted_at');
 57Ôćĺ
 58Ôćĺ			if (excludeIds.length > 0) {
 59Ôćĺ				queryA.whereNotIn('style_id_b', excludeIds);
 60Ôćĺ				queryB.whereNotIn('style_id_a', excludeIds);
 61Ôćĺ			}
 62Ôćĺ
 63Ôćĺ			const results = await this.knexRead
 64Ôćĺ				.unionAll([queryA, queryB])
 65Ôćĺ				.orderBy('copurchase_count', 'desc')
 66Ôćĺ				.limit(limit);
 67Ôćĺ
 68Ôćĺ			this.logger.debug(`Found ${results.length} copurchases for style ${styleId}`);
 69Ôćĺ
 70Ôćĺ			return results.map(
 71Ôćĺ				(row: {
 72Ôćĺ					paired_style_id: number | string;
 73Ôćĺ					copurchase_count: number | string;
 74Ôćĺ				}) => ({
 75Ôćĺ					paired_style_id: Number(row.paired_style_id),
 76Ôćĺ					copurchase_count: Number(row.copurchase_count),
 77Ôćĺ				}),
 78Ôćĺ			);
 79Ôćĺ		} catch (error: unknown) {
 80Ôćĺ			const err = error instanceof Error ? error : new Error(String(error));
 81Ôćĺ			this.logger.error(
 82Ôćĺ				`Failed to find top copurchases for style ${styleId}: ${err.message}`,
 83Ôćĺ			);
 84Ôćĺ			throw err;
 85Ôćĺ		}
 86Ôćĺ	}
