 88Ôćĺ	async findTopCopurchasesDiversified({
 89Ôćĺ		styleId,
 90Ôćĺ		limit = 4,
 91Ôćĺ		excludeIds = [],
 92Ôćĺ		diversifyCategories = false,
 93Ôćĺ		favorOppositeType = false,
 94Ôćĺ		seedStyleType,
 95Ôćĺ	}: {
 96Ôćĺ		styleId: number;
 97Ôćĺ		limit?: number;
 98Ôćĺ		excludeIds?: number[];
 99Ôćĺ		diversifyCategories?: boolean;
100Ôćĺ		favorOppositeType?: boolean;
101Ôćĺ		seedStyleType?: string | null | undefined;
102Ôćĺ	}): Promise<
103Ôćĺ		{
104Ôćĺ			paired_style_id: number;
105Ôćĺ			copurchase_count: number;
106Ôćĺ			primary_category_id: number;
107Ôćĺ			style_type: string | null;
108Ôćĺ		}[]
109Ôćĺ	> {
110Ôćĺ		const dto = plainToInstance(FindTopCopurchasesDiversifiedDto, {
111Ôćĺ			styleId,
112Ôćĺ			limit,
113Ôćĺ			excludeIds,
114Ôćĺ			diversifyCategories,
115Ôćĺ			favorOppositeType,
116Ôćĺ			seedStyleType,
117Ôćĺ		});
118Ôćĺ		const errors = await validate(dto);
119Ôćĺ		if (errors.length > 0) {
120Ôćĺ			throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
121Ôćĺ		}
122Ôćĺ
123Ôćĺ		try {
124Ôćĺ			const queryA = this.knexRead(this.tableName)
125Ôćĺ				.select('style_id_b as paired_style_id', 'copurchase_count')
126Ôćĺ				.where({ style_id_a: styleId })
127Ôćĺ				.whereNull('deleted_at');
128Ôćĺ
129Ôćĺ			const queryB = this.knexRead(this.tableName)
130Ôćĺ				.select('style_id_a as paired_style_id', 'copurchase_count')
131Ôćĺ				.where({ style_id_b: styleId })
132Ôćĺ				.whereNull('deleted_at');
133Ôćĺ
134Ôćĺ			if (excludeIds.length > 0) {
135Ôćĺ				queryA.whereNotIn('style_id_b', excludeIds);
136Ôćĺ				queryB.whereNotIn('style_id_a', excludeIds);
137Ôćĺ			}
138Ôćĺ
139Ôćĺ			const pairsSubquery = this.knexRead.unionAll([queryA, queryB]).as('pairs');
140Ôćĺ
141Ôćĺ			const baseQuery = this.knexRead
142Ôćĺ				.select(
143Ôćĺ					'pairs.paired_style_id',
144Ôćĺ					'pairs.copurchase_count',
145Ôćĺ					'mv.primary_category_id',
146Ôćĺ					'mv.style_type',
147Ôćĺ				)
148Ôćĺ				.from(pairsSubquery)
149Ôćĺ				.join(TABLE_NAME_STYLES_MV + ' as mv', function () {
150Ôćĺ					this.on('mv.style_id', '=', 'pairs.paired_style_id').andOnNull('mv.deleted_at');
151Ôćĺ				});
152Ôćĺ
153Ôćĺ			let query: Knex.QueryBuilder;
154Ôćĺ
155Ôćĺ			if (diversifyCategories) {
156Ôćĺ				query = this.knexRead
157Ôćĺ					.with(
158Ôćĺ						'copurchases',
159Ôćĺ						baseQuery
160Ôćĺ							.clone()
161Ôćĺ							.select(
162Ôćĺ								this.knexRead.raw(
163Ôćĺ									'ROW_NUMBER() OVER (PARTITION BY mv.primary_category_id ORDER BY pairs.copurchase_count DESC) AS rn',
164Ôćĺ								),
165Ôćĺ							),
166Ôćĺ					)
167Ôćĺ					.select(
168Ôćĺ						'paired_style_id',
169Ôćĺ						'copurchase_count',
170Ôćĺ						'primary_category_id',
171Ôćĺ						'style_type',
172Ôćĺ					)
173Ôćĺ					.from('copurchases')
174Ôćĺ					.where('rn', 1);
175Ôćĺ			} else {
176Ôćĺ				query = baseQuery;
177Ôćĺ			}
178Ôćĺ
179Ôćĺ			if (favorOppositeType) {
180Ôćĺ				if (seedStyleType) {
181Ôćĺ					query.orderByRaw('CASE WHEN style_type != ? THEN 0 ELSE 1 END', [
182Ôćĺ						seedStyleType,
183Ôćĺ					]);
184Ôćĺ				} else {
185Ôćĺ					query.orderByRaw('CASE WHEN style_type IS NOT NULL THEN 0 ELSE 1 END');
186Ôćĺ				}
187Ôćĺ			}
188Ôćĺ
189Ôćĺ			query.orderBy('copurchase_count', 'desc').limit(limit);
190Ôćĺ
191Ôćĺ			const results = (await query) as ICopurchaseRow[];
192Ôćĺ
193Ôćĺ			this.logger.debug(
194Ôćĺ				`Found ${results.length} diversified copurchases for style ${styleId}`,
195Ôćĺ			);
196Ôćĺ
197Ôćĺ			return results.map((row: ICopurchaseRow) => ({
198Ôćĺ				paired_style_id: Number(row.paired_style_id),
199Ôćĺ				copurchase_count: Number(row.copurchase_count),
200Ôćĺ				primary_category_id: Number(row.primary_category_id),
201Ôćĺ				style_type: row.style_type,
202Ôćĺ			}));
203Ôćĺ		} catch (error: unknown) {
204Ôćĺ			const err = error instanceof Error ? error : new Error(String(error));
205Ôćĺ			this.logger.error(
206Ôćĺ				`Failed to find diversified copurchases for style ${styleId}: ${err.message}`,
207Ôćĺ			);
208Ôćĺ			throw err;
209Ôćĺ		}
210Ôćĺ	}
