212Ôćĺ	async bulkInsert(
213Ôćĺ		pairs: {
214Ôćĺ			styleIdA: number;
215Ôćĺ			styleIdB: number;
216Ôćĺ			copurchaseCount: number;
217Ôćĺ		}[],
218Ôćĺ	): Promise<void> {
219Ôćĺ		try {
220Ôćĺ			const dataToInsert = pairs.map((pair) => {
221Ôćĺ				const minId = Math.min(pair.styleIdA, pair.styleIdB);
222Ôćĺ				const maxId = Math.max(pair.styleIdA, pair.styleIdB);
223Ôćĺ
224Ôćĺ				return {
225Ôćĺ					_id: randomUUID(),
226Ôćĺ					style_id_a: minId,
227Ôćĺ					style_id_b: maxId,
228Ôćĺ					copurchase_count: pair.copurchaseCount,
229Ôćĺ					created_at: this.knexWrite.fn.now(),
