**Interface Pattern (IStyleBase example):**
```typescript
export interface IStyleBase {
  _id: string;                               // UUID primary key
  style_id: number;
  // ... domain fields
  created_at: Date;
  updated_at: Date;
  deleted_at: Date | null;                  // Soft delete marker
}

export type IDomainCreate = Omit<IStyleBase, '_id' | 'created_at' | 'updated_at' | 'deleted_at'>;
export type IDomainUpdate = Partial<Omit<IStyleBase, '_id' | 'created_at' | 'updated_at' | 'deleted_at'>>;
```

**DTO Pattern with class-validator:**
```typescript
export class BaseStyleDto {
  @IsUUID()
  @IsNotEmpty()
  _id: string;

  @IsOptional()
  @IsArray()
  @IsInt({ each: true })
  @Transform(({ value }: { value: number[] | string }) => {
    if (Array.isArray(value)) return value;
    if (typeof value === 'string') {
      try {
        return JSON.parse(value) as number[];
      } catch {
        return [];
      }
    }
    return [];
  })
  categories_ids: number[] | null;

  // ... more fields
}

// OmitType removes _id, created_at, updated_at, deleted_at
export class CreateStyleDto extends OmitType(BaseStyleDto, [
  '_id', 'created_at', 'updated_at', 'deleted_at',
] as const) {}

export class UpdateStyleDto extends PartialType(
  OmitType(BaseStyleDto, ['_id', 'created_at', 'updated_at', 'deleted_at'] as const),
) {}
```

**Key DTO Patterns:**
- Use `@Transform` for JSON parsing (JSON columns stored as strings)
- Use `@Transform` for type coercion (tinyint booleans Ôćĺ boolean)
- `@IsOptional()` precedes type validators for nullable fields
- `@IsNotEmpty()` for non-nullable fields

