### 5. MODEL LAYER CONVENTIONS

**File Example:** `/Users/4thwithme/Documents/repo/recommendations-service/src/modules/db/styles/models/style.model.ts`

**Standard Structure:**
```typescript
@Injectable()
export class DomainModel {
  private readonly logger = new Logger(DomainModel.name);
  private readonly tableName = TABLE_NAME_X;

  constructor(
    @InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
    @InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
  ) {}

  // All methods wrapped in try/catch with logging
  async methodName(): Promise<ReturnType> {
    try {
      // Validate input DTO if writing
      const dto = plainToInstance(BaseDto, input);
      const errors = await validate(dto);
      if (errors.length > 0) {
        throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
      }

      // Execute query
      const result = await this.knexRead(this.tableName)...;

      // Validate output DTO
      const outputDto = plainToInstance(BaseDto, result);
      const outputErrors = await validate(outputDto);
      if (outputErrors.length > 0) {
        throw new Error(...);
      }

      this.logger.debug('Success message');
      return instanceToPlain(result) as ReturnType;
    } catch (error) {
      this.logger.error(`Failed: ${(error as Error).message}`);
      throw error;
    }
  }

  private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
    return errors
      .map((error) => `${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`)
      .join('; ');
  }
}
```

**Key Patterns:**
- All methods have try/catch with error logging
- Input validation: `plainToInstance()` + `validate()`
- Output validation: same pattern
- Return `instanceToPlain()` to convert back to plain objects
- Log levels: `debug` for success, `warn` for not-found, `error` for failures

**Advanced Upsert Pattern with Transactions:**
```typescript
async upsertStyle({
  data,
}: {
  data: Partial<IStyleCreate> & { style_id: IStyleBase['style_id'] };
}): Promise<IStyleBase> {
  // Validate input first
  const dto = plainToInstance(BaseStyleDto, data);
  const errors = await validate(dto, { skipMissingProperties: true });
  if (errors.length > 0) throw new Error(...);

  const upsertedStyle: IStyleBase = await this.knexWrite.transaction(async (trx) => {
    const existing = await trx<IStyleBase>(this.tableName)
      .where({ style_id: data.style_id })
      .whereNull('deleted_at')
      .first();

    if (existing) {
      // Update existing
      const updateData: Record<string, unknown> = {
        updated_at: trx.fn.now(),
      };
      // Handle JSON fields specially
      Object.keys(data).forEach((key) => {
        if (key === 'categories_ids' || key === 'sizes') {
          updateData[key] = JSON.stringify(data[key as keyof typeof data] ?? []);
        } else {
          updateData[key] = data[key as keyof typeof data];
        }
      });
      await trx(this.tableName)
        .where({ style_id: data.style_id })
        .whereNull('deleted_at')
        .update(updateData);
    } else {
      // Insert new
      const _id = randomUUID();
      const insertData = {
        _id,
        ...data,
        categories_ids: JSON.stringify(data.categories_ids ?? []),
        created_at: trx.fn.now(),
        updated_at: trx.fn.now(),
      };
      await trx(this.tableName).insert(insertData);
    }

    return await trx<IStyleBase>(this.tableName)
      .where({ style_id: data.style_id })
      .whereNull('deleted_at')
      .first();
  });

  return this.parseStyleData({ styleData: plainData });
}
```

**Multi-Model Transactions:**
```typescript
async saveCompleteStyle({
  styleData,
  colors,
  defaultUnitPrices,
}: {
  styleData: Partial<IStyleCreate> & { style_id: IStyleBase['style_id'] };
  colors: Omit<IStyleColorCreate, 'style_id'>[];
  defaultUnitPrices: Omit<IDefaultUnitPriceCreate, 'style_id'>[];
}): Promise<void> {
  await this.knexWrite.transaction(async (trx) => {
    await this.upsertStyleWithTransaction({ trx, data: styleData });
    for (const color of colors) {
      await this.styleColorModel.upsertStyleWithTransaction({ trx, data: { ...color, style_id: styleData.style_id } });
    }
    for (const priceData of defaultUnitPrices) {
      await this.defaultUnitPriceModel.upsertWithTransaction({ trx, data: { ...priceData, style_id: styleData.style_id } });
    }
  });
}
```

