### 7. MIGRATIONS SYSTEM

**File Example:** `/Users/4thwithme/Documents/repo/recommendations-service/src/migrations/20251125120000_create_styles_mv_table.ts`

**Pattern:**
```typescript
import { Logger } from '@nestjs/common';
import { TABLE_NAME_STYLES, TABLE_NAME_STYLES_MV } from '@constants/db.constant';
import type { Knex } from 'knex';

const logger = new Logger('20251125120000_create_styles_mv_table.ts');

export async function up(knex: Knex): Promise<void> {
  logger.log('Creating styles_mv table');

  await knex.transaction(async (trx) => {
    const tableExists = await trx.schema.hasTable(TABLE_NAME_STYLES_MV);

    if (!tableExists) {
      await trx.schema.createTable(TABLE_NAME_STYLES_MV, (table) => {
        table.uuid('_id').primary().notNullable();
        table.bigint('style_id').notNullable();

        // Regular columns
        table.string('name', 255).nullable();
        table.timestamp('created_at').defaultTo(trx.fn.now()).notNullable();
        table.timestamp('updated_at').defaultTo(trx.fn.now()).notNullable();
        table.timestamp('deleted_at').nullable();

        // Indexes
        table.unique(['style_id'], { predicate: trx.whereNull('deleted_at') });
        table.index(['primary_category_id', 'deleted_at']);

        // Foreign key
        table.foreign('style_id', 'fk_styles_mv_style_id')
          .references('style_id')
          .inTable(TABLE_NAME_STYLES)
          .onDelete('CASCADE');
      });

      logger.log('Successfully created styles_mv table');
    } else {
      logger.log('styles_mv table already exists, skipping');
    }
  });
}

export async function down(knex: Knex): Promise<void> {
  logger.log('Dropping styles_mv table');

  await knex.transaction(async (trx) => {
    await trx.schema.dropTableIfExists(TABLE_NAME_STYLES_MV);
  });
}
```

**Migration Commands:**
```bash
npm run migrate:make <name>        # Generate timestamped file in src/migrations/
npm run migrate                    # Run all pending migrations
npm run migrate:up                 # Run next single migration
npm run migrate:down               # Rollback last migration
npm run migrate:prod               # Run in production
```

**Migration Rules:**
- Always wrap in `knex.transaction(async (trx) => { ... })`
- Never edit existing migration; create new one instead
- Use table name constants (never raw strings)
- Check `tableExists` before creating to make migration idempotent
- Use conditional predicates for soft delete indexes: `{ predicate: trx.whereNull('deleted_at') }`
- Use `knexfile.ts` in project root for migration config

