### 8. KNEX QUERY BUILDER PATTERNS

**Soft Delete Queries:**
```typescript
// Always filter soft-deleted rows
await this.knexRead(this.tableName)
  .where({ style_id: styleId })
  .whereNull('deleted_at')
  .first();

// Soft delete (never hard delete)
await this.knexWrite(this.tableName)
  .where({ style_id: styleId })
  .whereNull('deleted_at')
  .update({
    deleted_at: this.knexWrite.fn.now(),
    updated_at: this.knexWrite.fn.now(),
  });
```

**Complex Queries:**
```typescript
// Union All for bidirectional relationships
const queryA = this.knexRead(this.tableName)
  .select('style_id_b as paired_style_id', 'copurchase_count')
  .where({ style_id_a: styleId })
  .whereNull('deleted_at');

const queryB = this.knexRead(this.tableName)
  .select('style_id_a as paired_style_id', 'copurchase_count')
  .where({ style_id_b: styleId })
  .whereNull('deleted_at');

const results = await this.knexRead
  .unionAll([queryA, queryB])
  .orderBy('copurchase_count', 'desc')
  .limit(limit);

// Window functions with CTE
const query = this.knexRead
  .with(
    'copurchases',
    baseQuery
      .select(
        this.knexRead.raw(
          'ROW_NUMBER() OVER (PARTITION BY primary_category_id ORDER BY copurchase_count DESC) AS rn',
        ),
      ),
  )
  .select('paired_style_id', 'copurchase_count', 'primary_category_id')
  .from('copurchases')
  .where('rn', 1);

// Raw SQL for complex expressions
query.orderByRaw('COUNT(*) desc');
query.orderByRaw('CASE WHEN style_type != ? THEN 0 ELSE 1 END', [seedStyleType]);

// Joins with callback
.join(TABLE_NAME_STYLES_MV + ' as mv', function () {
  this.on('mv.style_id', '=', 'pairs.paired_style_id').andOnNull('mv.deleted_at');
});

// Bulk upsert with conflict resolution
await this.knexWrite(this.tableName)
  .insert(batch)
  .onConflict(['primary_category_id', 'edge_id'])
  .merge(['edge_weight', 'updated_at', 'deleted_at']);
